async function main() {
  console.log(`Total updates: ${updates.length}`);
  let successCount = 0;
  let failCount = 0;

  for (const update of updates) {
    const { slug, description, metaDescription } = update;
    const wordCount = description.split(/\s+/).length;
    const metaLen = metaDescription.length;

    console.log(`\n[${slug}]`);
    console.log(`  Description words: ${wordCount}`);
    console.log(`  Meta length: ${metaLen} chars`);

    if (wordCount < 250) {
      console.log(`  WARNING: Description under 250 words!`);
    }
    if (metaLen < 130 || metaLen > 155) {
      console.log(`  WARNING: Meta description length ${metaLen} outside 130-155 range!`);
    }

    try {
      const result = await prisma.product.update({
        where: { slug },
        data: { description, metaDescription },
      });
      console.log(`  Updated successfully (id: ${result.id})`);
      successCount++;
    } catch (err) {
      console.log(`  FAILED: ${err.message}`);
      failCount++;
    }
  }

  console.log(`\n=== SUMMARY ===`);
  console.log(`Success: ${successCount}`);
  console.log(`Failed: ${failCount}`);
  console.log(`Total: ${updates.length}`);
}

main()
  .catch(console.error)
  .finally(() => prisma.$disconnect());
